// pubspec: flutter_bloc: ^8.1, equatable: ^2.0
import 'package:equatable/equatable.dart';
import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';

// 1. Events — user intents / external triggers
sealed class CartEvent extends Equatable { const CartEvent(); @override List<Object?> get props => []; }
class CartFetched extends CartEvent { const CartFetched(); }
class CartItemAdded extends CartEvent {
  const CartItemAdded(this.name);
  final String name;
  @override List<Object?> get props => [name];
}
class CartCleared extends CartEvent { const CartCleared(); }

// 2. States — UI-consumable snapshots
sealed class CartState extends Equatable { const CartState(); @override List<Object?> get props => []; }
class CartInitial extends CartState { const CartInitial(); }
class CartLoading extends CartState { const CartLoading(); }
class CartLoaded extends CartState {
  const CartLoaded(this.items);
  final List<String> items;
  @override List<Object?> get props => [items];
}
class CartError extends CartState {
  const CartError(this.message);
  final String message;
  @override List<Object?> get props => [message];
}

// 3. The Bloc — event handlers
class CartBloc extends Bloc<CartEvent, CartState> {
  CartBloc(this._repo) : super(const CartInitial()) {
    on<CartFetched>(_onFetched);
    on<CartItemAdded>(_onAdded);
    on<CartCleared>(_onCleared);
  }

  final CartRepository _repo;

  Future<void> _onFetched(CartFetched _, Emitter<CartState> emit) async {
    emit(const CartLoading());
    try {
      final items = await _repo.fetchCart();
      emit(CartLoaded(items));
    } catch (e) {
      emit(CartError(e.toString()));
    }
  }

  Future<void> _onAdded(CartItemAdded event, Emitter<CartState> emit) async {
    final current = state;
    if (current is CartLoaded) {
      emit(CartLoaded([...current.items, event.name]));
      await _repo.saveCart([...current.items, event.name]);
    }
  }

  Future<void> _onCleared(CartCleared _, Emitter<CartState> emit) async {
    emit(const CartLoaded([]));
    await _repo.saveCart([]);
  }
}

// 4. UI — provide the bloc, then consume states
void main() {
  runApp(MaterialApp(
    home: BlocProvider(
      create: (_) => CartBloc(CartRepository())..add(const CartFetched()),
      child: const CartScreen(),
    ),
  ));
}

class CartScreen extends StatelessWidget {
  const CartScreen({super.key});
  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Cart')),
    body: BlocBuilder<CartBloc, CartState>(
      builder: (context, state) => switch (state) {
        CartInitial() => const Center(child: Text('idle')),
        CartLoading() => const Center(child: CircularProgressIndicator()),
        CartError(:final message) => Center(child: Text('Error: $message')),
        CartLoaded(:final items) => ListView(children: items.map((s) => Text(s)).toList()),
      },
    ),
    floatingActionButton: FloatingActionButton(
      onPressed: () => context.read<CartBloc>().add(const CartItemAdded('apple')),
      child: const Icon(Icons.add),
    ),
  );
}

class CartRepository {  // stub
  Future<List<String>> fetchCart() async => ['banana'];
  Future<void> saveCart(List<String> items) async {}
}

// Cubit skips events. Methods on the cubit directly emit state.
class CartCubit extends Cubit<CartState> {
  CartCubit(this._repo) : super(const CartInitial());

  final CartRepository _repo;

  Future<void> fetch() async {
    emit(const CartLoading());
    try {
      emit(CartLoaded(await _repo.fetchCart()));
    } catch (e) {
      emit(CartError(e.toString()));
    }
  }

  void add(String name) {
    final s = state;
    if (s is CartLoaded) emit(CartLoaded([...s.items, name]));
  }
}

// UI:
context.read<CartCubit>().fetch();     // no event class needed
context.read<CartCubit>().add('apple');

// Trade-off: no explicit event names → less debuggable action trail.
// Cubit for simple cases; Bloc when you need the event log.

